import{_ as r,o,c as s,ag as a}from"./chunks/framework.D9bIGSBm.js";const p=JSON.parse('{"title":"定时执行消息","description":"","frontmatter":{},"headers":[],"relativePath":"features/scheduled-send.md","filePath":"features/scheduled-send.md"}'),e={name:"features/scheduled-send.md"};function n(d,t,l,g,c,i){return o(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="定时执行消息" tabindex="-1">定时执行消息 <a class="header-anchor" href="#定时执行消息" aria-label="Permalink to &quot;定时执行消息&quot;">​</a></h1><p>你可以让一条消息<strong>到点自动发送</strong>给 AI——延迟若干小时后跑一次，约定到某个具体时间跑，或者按固定间隔、Cron 表达式周期性重复。适合下班前留一句「明早 9 点帮我跑一遍测试并汇总」，或让某个任务每隔一段时间自动巡检（v0.7.2 起）。</p><blockquote><p>相关基础：<a href="/docs/features/conversation.html">对话面板</a>、<a href="/docs/features/tasks-and-workspaces.html">任务与工作区</a></p></blockquote><hr><h2 id="创建一条定时" tabindex="-1">创建一条定时 <a class="header-anchor" href="#创建一条定时" aria-label="Permalink to &quot;创建一条定时&quot;">​</a></h2><p>输入框工具栏的<strong>发送按钮左侧</strong>有一个<strong>时钟图标</strong>（定时执行）。</p><ol><li>像平时一样在输入框里<strong>写好要发送的内容</strong>（支持 <code>@</code> 引用文件、<code>/</code> 命令、图片等，与普通消息一致）。</li><li>点击<strong>时钟图标</strong>，弹出定时配置面板。</li><li>选择一种触发模式（见下），面板底部会<strong>预览下次触发时间</strong>。</li><li>点击<strong>创建定时</strong>完成挂载。</li></ol><div class="tip custom-block"><p class="custom-block-title">必须先填内容</p><p>定时面板的「创建定时」按钮只有在输入框<strong>已有内容</strong>时才可用——内容为空时按钮置灰，并提示「请先在输入框中填写要发送的内容」。这是因为定时发送的就是你此刻写好的那条消息。</p></div><div class="warning custom-block"><p class="custom-block-title">内容在创建时被「冻结」</p><p>点「创建定时」的那一刻，消息内容（含 <code>@</code> 文件、<code>/</code> 命令等片段）会被<strong>快照保存</strong>。之后你再改输入框不会影响已挂的定时；到点发送的永远是创建时的那份内容。</p></div><hr><h2 id="四种触发模式" tabindex="-1">四种触发模式 <a class="header-anchor" href="#四种触发模式" aria-label="Permalink to &quot;四种触发模式&quot;">​</a></h2><p>定时面板顶部用四个分段切换触发模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><strong>延迟</strong></td><td>从现在起延迟一段时间，<strong>只执行一次</strong></td><td>「3 小时后执行一次」</td></tr><tr><td><strong>指定时间</strong></td><td>在某个具体的日期与时刻执行一次</td><td>用内置日期时间选择器挑「明天 09:00」</td></tr><tr><td><strong>周期间隔</strong></td><td>每隔固定时长<strong>重复执行</strong></td><td>「每 30 分钟重复执行」</td></tr><tr><td><strong>Cron</strong></td><td>用 Cron 表达式定义周期，最灵活</td><td><code>0 9 * * 1-5</code>（工作日每天 9 点）</td></tr></tbody></table><ul><li><strong>延迟 / 周期间隔</strong>：填一个数字 + 单位（分钟 / 小时 / 天）。</li><li><strong>指定时间</strong>：用内置的<strong>日期时间选择器</strong>（内联日历 + 时 / 分下拉）挑选，无需输入文本；月份、星期等会跟随应用的语言设置显示。</li><li><strong>Cron</strong>：输入标准 Cron 表达式，面板会预览接下来几次触发时间，便于核对。</li></ul><div class="tip custom-block"><p class="custom-block-title">一次性 vs 周期</p><p>「延迟」和「指定时间」是<strong>一次性</strong>的，到点执行后该定时即结束；「周期间隔」和「Cron」会<strong>反复执行</strong>，直到你手动取消。</p></div><hr><h2 id="草稿态任务也能定时" tabindex="-1">草稿态任务也能定时 <a class="header-anchor" href="#草稿态任务也能定时" aria-label="Permalink to &quot;草稿态任务也能定时&quot;">​</a></h2><p>即使任务还是<strong>草稿</strong>（尚未发出过任何消息、还没正式落盘），也可以为它挂定时。点击时钟图标创建定时时，LoongCode 会先把草稿<strong>落盘成正式任务</strong>，再挂上定时，并清空输入框。此后该任务就会出现在任务列表中，到点自动发送你写好的那条消息。</p><hr><h2 id="查看与取消已挂的定时" tabindex="-1">查看与取消已挂的定时 <a class="header-anchor" href="#查看与取消已挂的定时" aria-label="Permalink to &quot;查看与取消已挂的定时&quot;">​</a></h2><h3 id="单个任务" tabindex="-1">单个任务 <a class="header-anchor" href="#单个任务" aria-label="Permalink to &quot;单个任务&quot;">​</a></h3><p>在该任务输入框的定时面板里，下方会列出<strong>当前任务已挂的所有定时</strong>，每条显示触发规则与下次触发时间，点条目右侧的<strong>取消</strong>即可删除。</p><p>定时按钮本身也会反映状态：当任务挂有启用中的定时时，<strong>时钟图标变为紫色</strong>，并在右上角显示一个<strong>数字角标</strong>标明已挂定时的数量。</p><h3 id="全局总览" tabindex="-1">全局总览 <a class="header-anchor" href="#全局总览" aria-label="Permalink to &quot;全局总览&quot;">​</a></h3><p>左侧栏底部（设置齿轮附近）有一个<strong>时钟入口</strong>，点击打开<strong>定时总览</strong>对话框，集中查看和管理<strong>所有任务</strong>的定时任务。没有任何定时时显示「暂无定时任务」。</p><hr><h2 id="任务行的紫色指示灯" tabindex="-1">任务行的紫色指示灯 <a class="header-anchor" href="#任务行的紫色指示灯" aria-label="Permalink to &quot;任务行的紫色指示灯&quot;">​</a></h2><p>挂了定时的任务，其任务行左侧的状态圆点会进入<strong>紫色定时态</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">指示灯</th><th>状态</th><th>含义</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="lc-dot lc-dot--schedule lc-dot--read"></span></td><td><strong>待命（armed）</strong></td><td>紫色但偏暗——已挂定时、正等待到点触发</td></tr><tr><td style="text-align:center;"><span class="lc-dot lc-dot--schedule lc-dot--schedule-hi"></span></td><td><strong>已触发未读（fired-unread）</strong></td><td>紫色高亮带光晕——定时已触发并发送了消息，但你还没查看</td></tr></tbody></table><p>指示灯的优先级是：<strong>提问中（蓝）&gt; 运行中（琥珀）&gt; 已触发未读（紫高亮）&gt; 待命（紫暗）&gt; 普通状态</strong>。也就是说任务正在运行或正在提问时，会优先显示对应颜色；空闲时若有定时，才显示紫色。</p><p>关于其余状态圆点颜色，见<a href="/docs/features/tasks-and-workspaces.html#任务状态">任务与工作区 → 任务状态</a>。</p><hr><h2 id="触发时机与边界行为" tabindex="-1">触发时机与边界行为 <a class="header-anchor" href="#触发时机与边界行为" aria-label="Permalink to &quot;触发时机与边界行为&quot;">​</a></h2><ul><li><strong>任务忙时排队</strong>：定时到点时，如果该任务<strong>正在运行</strong>一轮对话，本次触发会<strong>跳过当前 tick、稍后重试</strong>，不会打断正在进行的回合。</li><li><strong>应用关闭期间错过</strong>：如果定时应触发的时间点恰好处于应用未运行期间——<strong>一次性</strong>定时（延迟 / 指定时间）会被<strong>跳过并禁用</strong>（不补发）；<strong>周期性</strong>定时（周期间隔 / Cron）则<strong>前滚</strong>到下一个未来的触发点继续。</li><li><strong>执行期间锁输入</strong>：定时触发、消息正在发送时，输入框会被短暂锁定，避免与你手动输入冲突。</li></ul><div class="tip custom-block"><p class="custom-block-title">配置如何生效</p><p>定时<strong>到点发送时</strong>会读取该任务当前的 CLI、模型、思考深度等执行配置（即「跟随任务的实时设置」），而<strong>消息内容</strong>则是创建定时时冻结的那一份。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解定时执行之后，可以进一步探索对话历史的代码快照与回滚功能，前往<a href="/docs/features/checkpoints.html">代码检查点</a>继续学习。</p>',38)])])}const u=r(e,[["render",n]]);export{p as __pageData,u as default};
